def _complete_usernames(
    ctx: Context, param: Parameter, incomplete: str
) -> list[str]:
    """Complete system usernames, used by :attr:`Option.auto_complete`."""
    try:
        import pwd

        names = [entry.pw_name for entry in pwd.getpwall()]
    except ImportError:
        # The pwd module is only available on Unix platforms.
        import getpass

        names = [getpass.getuser()]

    return [name for name in names if name.startswith(incomplete)]


def _complete_git_branches(
    ctx: Context, param: Parameter, incomplete: str
) -> list[str]:
    """Complete local and remote git branch names, used by
    :attr:`Option.auto_complete`.
    """
    try:
        output = subprocess.run(
            ["git", "branch", "-a", "--format=%(refname:short)"],
            capture_output=True,
            text=True,
            check=True,
        ).stdout
    except (OSError, subprocess.CalledProcessError):
        return []

    branches = {line.strip() for line in output.splitlines() if line.strip()}
    return [branch for branch in branches if branch.startswith(incomplete)]


def _complete_filesystem_paths(
    ctx: Context, param: Parameter, incomplete: str
) -> list[CompletionItem]:
    """Complete filesystem paths, used by :attr:`Option.auto_complete`."""
    return Path().shell_complete(ctx, param, incomplete)


